    name TEXT NOT NULL,
    country TEXT,
    role TEXT,
    batting_rating INTEGER,
    bowling_rating INTEGER,
    ovr INTEGER,
    bowler_type TEXT,
    buy_price BIGINT,
    image_url TEXT,
    created_at TIMESTAMP WITH TIME ZONE DEFAULT timezone('utc'::text, now()),
    tier TEXT,
    batting_archetype TEXT,
    bowling_archetype TEXT
);

